from functools import wraps

class TransactionLock:
    def __init__(self):
        self._lock = threading.Lock()

    def acquire(self):
        self._lock.acquire()

    def release(self):
        self._lock.release()

class ComptrollerSystem:
    def __init__(self):
        self.transaction_lock = TransactionLock()
        self.queue = Queue()

    def transactional(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            self.transaction_lock.acquire()
            try:
                return func(*args, **kwargs)
            except Exception as e:
                raise e
            finally:
                self.transaction_lock.release()
        return wrapper

    def add_transaction(self, account_number, amount, transaction_type):
        self.queue.put((account_number, amount, transaction_type))

    @transactional
    def process_transactions(self):
        while not self.queue.empty():
            account_number, amount, transaction_type = self.queue.get()
            if transaction_type == 'deposit':
                self.deposit(account_number, amount)
            elif transaction_type == 'withdrawal':
                self.withdraw(account_number, amount)

