from enum import Enum

class ATMStatus(Enum):
    AVAILABLE = 1
    BUSY = 2
    OFFLINE = 3

class ATM:
    def __init__(self, id):
        self.id = id
        self.status = ATMStatus.AVAILABLE
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if self.status == ATMStatus.AVAILABLE:
                self.status = ATMStatus.BUSY
                try:
                    # simulate transaction
                    time.sleep(1)
                    print(f"Withdrawal of {amount} from ATM {self.id} successful")
                except Exception as e:
                    print(f"Error during withdrawal from ATM {self.id}: {str(e)}")
                finally:
                    self.status = ATMStatus.AVAILABLE
            else:
                print(f"ATM {self.id} is currently busy or offline")

    def deposit(self, amount):
        with self.lock:
            if self.status == ATMStatus.AVAILABLE:
                self.status = ATMStatus.BUSY
                try:
                    # simulate transaction
                    time.sleep(1)
                    print(f"Deposit of {amount} to ATM {self.id} successful")
                except Exception as e:
                    print(f"Error during deposit to ATM {self.id}: {str(e)}")
                finally:
                    self.status = ATMStatus.AVAILABLE
            else:
                print(f"ATM {self.id} is currently busy or offline")

