        self.atms = []
        self.queue = Queue()
        self.lock = threading.Lock()

    def add_atm(self, atm):
        with self.lock:
            self.atms.append(atm)

    def remove_atm(self, atm_id):
        with self.lock:
            self.atms = [atm for atm in self.atms if atm.id != atm_id]

    def process_transaction(self, atm_id, transaction_type, amount):
