        self.atms = {}
        self.lock = threading.Lock()
        self.transactions = {}

    def add_atm(self, atm_id):
        with self.lock:
            if atm_id not in self.atms:
                self.atms[atm_id] = {'balance': 0, 'status': 'online'}
                self.transactions[atm_id] = []

    def remove_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                del self.atms[atm_id]
                del self.transactions[atm_id]

    def deposit(self, atm_id, amount):
        with self.lock:
            if atm_id in self.atms and self.atms[atm_id]['status'] == 'online':
                self.atms[atm_id]['balance'] += amount
                self.transactions[atm_id].append({'type': 'deposit', 'amount': amount})
                return True
            return False

    def withdraw(self, atm_id, amount):
        with self.lock:
            if atm_id in self.atms and self.atms[atm_id]['status'] == 'online' and self.atms[atm_id]['balance'] >= amount:
                self.atms[atm_id]['balance'] -= amount
                self.transactions[atm_id].append({'type': 'withdrawal', 'amount': amount})
                return True
            return False

    def get_balance(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                return self.atms[atm_id]['balance']
            return None

    def get_transactions(self, atm_id):
        with self.lock:
            if atm_id in self.transactions:
                return self.transactions[atm_id]
            return None

    def freeze_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                self.atms[atm_id]['status'] = 'frozen'
                return True
            return False

    def unfreeze_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms and self.atms[atm_id]['status'] == 'frozen':
                self.atms[atm_id]['status'] = 'online'
                return True
            return False

