    def __init__(self):
        self.lock = threading.Lock()
        self.transactions = {}
        self.accounts = {}

    def create_account(self, account_id, balance):
        with self.lock:
            if account_id in self.accounts:
                raise ValueError("Account already exists")
            self.accounts[account_id] = balance

    def transfer_funds(self, sender_id, recipient_id, amount):
        with self.lock:
            if sender_id not in self.accounts or recipient_id not in self.accounts:
                raise ValueError("Invalid account")
            if self.accounts[sender_id] < amount:
                raise ValueError("Insufficient funds")
            self.accounts[sender_id] -= amount
            self.accounts[recipient_id] += amount
            transaction_id = uuid.uuid4()
            self.transactions[transaction_id] = (sender_id, recipient_id, amount)
            return transaction_id

    def get_balance(self, account_id):
        with self.lock:
            return self.accounts.get(account_id, 0)

    def verify_transaction(self, transaction_id):
        with self.lock:
            transaction = self.transactions.get(transaction_id)
            if not transaction:
                raise ValueError("Transaction not found")
            sender_id, recipient_id, amount = transaction
            return self.accounts[sender_id] + amount == self.accounts[recipient_id] - amount

    def rollback_transaction(self, transaction_id):
        with self.lock:
            transaction = self.transactions.get(transaction_id)
            if not transaction:
                raise ValueError("Transaction not found")
            sender_id, recipient_id, amount = transaction
            self.accounts[sender_id] += amount
            self.accounts[recipient_id] -= amount
            del self.transactions[transaction_id]

