        with self.lock:
            if account_id in self.accounts:
                self.accounts[account_id] += amount
                self.transactions.append(("deposit", account_id, amount))
                self.queue.put(("deposit", account_id, amount))
            else:
                raise ValueError("Account not found")

    def withdraw(self, account_id: str, amount: float):
        with self.lock:
            if account_id in self.accounts:
                if self.accounts[account_id] >= amount:
                    self.accounts[account_id] -= amount
                    self.transactions.append(("withdrawal", account_id, amount))
                    self.queue.put(("withdrawal", account_id, amount))
                else:
                    raise ValueError("Insufficient funds")
            else:
                raise ValueError("Account not found")

    def get_balance(self, account_id: str):
        with self.lock:
            if account_id in self.accounts:
                return self.accounts[account_id]
            else:
                raise ValueError("Account not found")

