        while not self.queue.empty():
            transaction = self.queue.get()
            if transaction[0] == "deposit":
                print(f"Processed deposit of {transaction[2]} to account {transaction[1]}")
            elif transaction[0] == "withdrawal":
                print(f"Processed withdrawal of {transaction[2]} from account {transaction[1]}")

    def verify_transactions(self):
        with self.lock:
            for transaction in self.transactions:
                if transaction[0] == "deposit":
                    if self.accounts[transaction[1]] < transaction[2]:
                        print(f"Error: deposit of {transaction[2]} to account {transaction[1]} is inconsistent")
                elif transaction[0] == "withdrawal":
