class CashDispenser:
    def __init__(self):
        self.bill_amount = 0
        self.blank_space = 100
        self.cash_withdrawn = 0
        self.failed_transactions = 0

    def add_bill(self, amount):
        if self.blank_space >= amount:
            self.bill_amount += amount
            self.blank_space -= amount
            print("Bill added successfully")
        else:
            print("Insufficient space")

    def withdraw_cash(self, amount):
        if amount <= self.bill_amount:
            self.bill_amount -= amount
            self.cash_withdrawn += amount
            print("Cash withdrawn successfully")
        else:
            self.failed_transactions += 1
            print("Insufficient balance")

    def get_status(self):
        print("Bill Amount: ", self.bill_amount)
        print("Blank Space: ", self.blank_space)
        print("Cash Withdrawn: ", self.cash_withdrawn)
        print("Failed Transactions: ", self.failed_transactions)


